### src/router.js

```javascript
import path from "path";

import { searchAnime } from "./controllers/anime-search.js";
import express from "express";
import { TopAnime } from "./controllers/top-anime.js";
import { animeDetails } from "./controllers/anime-details.js";
import { cacheMiddleware } from "./middleware/cache.js";
export const router = express.Router();

router.get("/search/:entityType", (req, res) => {
  res.sendFile(path.join(import.meta.dirname, "..", "public", "search", "index.html"));
});

router.get("/:entityType/:id", (req, res) => {
  res.sendFile(path.join(import.meta.dirname, "..", "public", "entity", "index.html"));
});

router.use(cacheMiddleware); // This line caches whats after only

router.get("/api/:entityType/top", TopAnime);
router.get("/api/:entityType/search", searchAnime);
router.get("/api/:entityType/:id", animeDetails);
```

### src/controllers/anime-search.js

```javascript
export const searchAnime = (req, res) => {
  const { q = "", page = 1 } = req.query;
  const { entityType = "anime" } = req.params;
  if (!["anime", "manga"].includes(entityType)) {
    return res.status(400).json("Only manga and anime are allowed values");
  }
  if (q.length === 0) {
    return res.status(400).json({ message: "Please search with a query" });
  }

  fetch(`https://api.jikan.moe/v4/${entityType}?q=${q}&page=${page}`)
    .then((response) => {
      if (!response.ok) {
        throw { status: response.status, message: "upstream error" };
      }
      return response.json();
    })

    .then((data) => res.json(data))
    .catch((error) => {
      const status = error.status || 500;
      const message = error.message || "Internal server error";
      res.status(status).json({ message });
    });
};
```

### src/controllers/anime-details.js

```javascript
export const animeDetails = (req, res) => {
  const id = req.params.id;
  const { entityType } = req.params;
  if (!["anime", "manga"].includes(entityType)) {
    return res.status(400).json("Only manga and anime are allowed values");
  }
  fetch(`https://api.jikan.moe/v4/${entityType}/${id}`)
    .then((response) => response.json())
    .then((data) => res.json(data))
    .catch((error) => {
      console.log(error);
      res.status(500).json({ message: "Internal server error: " + error.message });
    });
};
```

### src/controllers/top-anime.js

```javascript
export const TopAnime = (req, res) => {
  const { entityType } = req.params;
  if (!["anime", "manga"].includes(entityType)) {
    return res.status(400).json("Only manga and anime are allowed values");
  }

  fetch(`https://api.jikan.moe/v4/top/${entityType}?limit=10`)
    .then((response) => response.json())
    .then((data) => res.json(data))
    .catch((error) => {
      console.dir(JSON.stringify(error));
      res.status(500).json({ message: "Internal server error: " + error.message });
    });
};
```

### src/middleware/cache.js

```javascript
import { LRUCache } from "lru-cache";

const cache = new LRUCache({
  max: 1000,
  ttl: 1000 * 60 * 15,
});

export const cacheMiddleware = (req, res, next) => {
  const cacheKey = `${req.method}:${req.url}`;
  // console.debug(cacheKey, "cached:", cache.has(cacheKey));
  if (cache.has(cacheKey)) {
    const { data } = cache.get(cacheKey);
    return res.json(data);
  }

  // Imad note: This is monkey patching the `res.json` call, i dont know of easier ways to pick up the response.body, that means if you dont use res.json it does not get cached.
  const oldResJson = res.json;

  res.json = function (data) {
    const time = Date.now();
    cache.set(cacheKey, { data, time });

    return oldResJson.call(this, data);
  };

  next();
};
```

