  cursor: pointer;
  outline: none;
  appearance: none;
  -webkit-appearance: none;
}

.search-bar input[type="text"] {
  flex: 1;
  background: transparent;
  border: none;
  color: var(--text-primary);
  padding: 10px 16px;
  font-size: 0.95rem;
  font-family: inherit;
  outline: none;
  min-width: 0;
}

.search-bar input[type="text"]::placeholder {
  color: var(--text-muted);
}

.search-bar button {
  background: var(--accent-gradient);
  color: #fff;
  border: none;
  border-radius: 36px;
  padding: 10px 22px;
  font-size: 0.85rem;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: opacity var(--transition), transform var(--transition);
  white-space: nowrap;
}

.search-bar button:hover {
  opacity: 0.9;
  transform: scale(1.02);
}

/* === Nav Brand === */
.nav-brand {
  text-align: center;
  padding: 28px 24px 0;
}

.nav-brand h1 {
  font-size: 1.6rem;
  font-weight: 700;
  background: var(--accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.nav-brand p {
  color: var(--text-muted);
  font-size: 0.85rem;
  margin-top: 2px;
}

/* === Cards === */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
  cursor: pointer;
  transition: transform var(--transition), box-shadow var(--transition), border-color var(--transition);
}

.card:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-lg);
  border-color: var(--accent);
}

.card img {
  width: 100%;
  aspect-ratio: 3/4;
  object-fit: cover;
  display: block;
}

.card-body {
  padding: 12px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.card-title {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.card-synopsis {
  font-size: 0.75rem;
  color: var(--text-secondary);
  line-height: 1.5;
  max-height: 54px;
  overflow-y: auto;
  scrollbar-width: thin;
  scrollbar-color: var(--bg-input) transparent;
}

.card-synopsis::-webkit-scrollbar {
  width: 4px;
}

.card-synopsis::-webkit-scrollbar-thumb {
  background: var(--bg-input);
  border-radius: 4px;
}

.card-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  font-size: 0.75rem;
  color: var(--text-muted);
}

.card-rating {
  display: flex;
  align-items: center;
  gap: 4px;
  color: var(--accent);
  font-weight: 600;
}

.card-rating::before {
  content: "★";
}

.card-episodes {
  color: var(--text-muted);
}

/* === Section Titles === */
.section-title {
  font-size: 1.2rem;
  font-weight: 700;
  color: var(--text-primary);
  padding: 20px 24px 12px;
}

/* === Pagination === */
.pagination {
  display: flex;
  justify-content: center;
  gap: 12px;
  padding: 24px;
}

.pagination button {
  background: var(--bg-secondary);
  color: var(--text-primary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px 24px;
  font-size: 0.85rem;
  font-family: inherit;
  font-weight: 500;
  cursor: pointer;
  transition: background var(--transition), border-color var(--transition);
}

.pagination button:hover:not(:disabled) {
  background: var(--bg-card-hover);
  border-color: var(--accent);
}

.pagination button:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* === Scrollbar global === */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--bg-input);
  border-radius: 4px;
}

/* === Loading Skeleton === */
.loading-text {
  color: var(--text-muted);
  text-align: center;
  padding: 40px;
  font-size: 0.9rem;
}

input.content:
/* Homepage-specific styles */

.horizontal-scroll {
  display: flex;
  gap: 16px;
  overflow-x: auto;
  padding: 0 24px 20px;
  scroll-snap-type: x mandatory;
  scroll-padding: 24px;
  -webkit-overflow-scrolling: touch;
}

.horizontal-scroll .card {
  flex: 0 0 200px;
  scroll-snap-align: start;
}

.horizontal-scroll .card img {
  height: 260px;
}

.horizontal-scroll .card-synopsis {
  max-height: 48px;
}

// Search form
document.getElementById("search-form").addEventListener("submit", (e) => {
  e.preventDefault();
  const q = document.getElementById("text").value;
  const type = document.getElementById("type").value;
  if (q.trim()) {
    window.location.href = `/search/${type}?q=${encodeURIComponent(q)}`;
  }
});

function render(data, entityType) {
  const container = document.getElementById(`${entityType}-container`);
  container.innerHTML = "";

  data.data.forEach((element) => {
    const card = document.createElement("div");
    card.className = "card";

    const img = document.createElement("img");
    img.src = element.images.jpg.image_url;
    img.alt = element.title;
    img.loading = "lazy";

    const body = document.createElement("div");
    body.className = "card-body";

    const title = document.createElement("div");
    title.className = "card-title";
    title.textContent = element.title;

    const synopsis = document.createElement("div");
    synopsis.className = "card-synopsis";
    synopsis.textContent = element.synopsis || "No synopsis available.";

    const meta = document.createElement("div");
    meta.className = "card-meta";

    const rating = document.createElement("span");
    rating.className = "card-rating";
    rating.textContent = element.score ?? "N/A";

    const episodes = document.createElement("span");
    episodes.className = "card-episodes";
    if (entityType === "anime") {
      episodes.textContent = element.episodes ? `${element.episodes} eps` : "? eps";
    } else {
      episodes.textContent = element.chapters ? `${element.chapters} ch` : "? ch";
    }

    meta.appendChild(rating);
    meta.appendChild(episodes);

    body.appendChild(title);
    body.appendChild(synopsis);
    body.appendChild(meta);

    card.appendChild(img);
    card.appendChild(body);

    card.addEventListener("click", () => {
      window.location.href = `/${entityType}/${element.mal_id}`;
    });

    container.appendChild(card);
  });
}

function fetchPage() {
  fetch("/api/anime/top")
    .then((response) => response.json())
    .then((data) => render(data, "anime"))
    .then(() => fetch("/api/manga/top"))
    .then((response) => response.json())
    .then((data) => render(data, "manga"));
}

fetchPage();

/* Search page specific styles */

.results-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(190px, 1fr));
  gap: 20px;
  padding: 16px 24px;
}

.results-grid .card img {
  height: 250px;
}

.results-grid .card-synopsis {
  max-height: 54px;
}

.no-results {
  grid-column: 1 / -1;
  text-align: center;
  color: var(--text-muted);
  padding: 60px 20px;
  font-size: 0.95rem;
}

const searchParams = new URLSearchParams(location.search);
let currentPage = Number(searchParams.get("page") || 1);
let searchQuery = searchParams.get("q");
let entityType = location.pathname.split("/")[2] || "anime";

const searchResultsContainer = document.getElementById("search-results");
const paginationContainer = document.getElementById("pagination");
const typeSelect = document.getElementById("type");
const textInput = document.getElementById("text");

typeSelect.value = entityType;
if (searchQuery) textInput.value = searchQuery;

document.getElementById("search-form").addEventListener("submit", (e) => {
  e.preventDefault();
  const q = textInput.value;
  const type = typeSelect.value;
  if (q.trim()) {
    window.location.href = `/search/${type}?q=${encodeURIComponent(q)}`;
  }
});

function renderResults(data) {
  const hasNextPage = data.pagination.has_next_page;
  const hasPreviousPage = data.pagination.current_page !== 1;

  searchResultsContainer.innerHTML = "";

  if (data.data.length === 0) {
    const msg = document.createElement("p");
    msg.className = "no-results";
    msg.textContent = "No results found. Try a different search.";
    searchResultsContainer.appendChild(msg);
    return;
  }

  data.data.forEach((element) => {
    const card = document.createElement("div");
    card.className = "card";

    const img = document.createElement("img");
    img.src = element.images.jpg.image_url;
    img.alt = element.title;
    img.loading = "lazy";

    const body = document.createElement("div");
    body.className = "card-body";

    const title = document.createElement("div");
    title.className = "card-title";
    title.textContent = element.title;

    const synopsis = document.createElement("div");
    synopsis.className = "card-synopsis";
    synopsis.textContent = element.synopsis || "No synopsis available.";

    const meta = document.createElement("div");
    meta.className = "card-meta";

    const rating = document.createElement("span");
    rating.className = "card-rating";
    rating.textContent = element.score ?? "N/A";

    const episodes = document.createElement("span");
    episodes.className = "card-episodes";
    if (entityType === "anime") {
      episodes.textContent = element.episodes ? `${element.episodes} eps` : "? eps";
    } else {
      episodes.textContent = element.chapters ? `${element.chapters} ch` : "? ch";
    }

    meta.appendChild(rating);
    meta.appendChild(episodes);

    body.appendChild(title);
    body.appendChild(synopsis);
    body.appendChild(meta);

    card.appendChild(img);
    card.appendChild(body);

    card.addEventListener("click", () => {
      window.location.href = `/${entityType}/${element.mal_id}`;
    });

    searchResultsContainer.appendChild(card);
  });

  // Pagination
  paginationContainer.innerHTML = "";

  const previous = document.createElement("button");
  previous.textContent = "← Previous";
  previous.disabled = !hasPreviousPage;
  previous.addEventListener("click", () => {
    if (currentPage > 1) {
      window.location.search = `?q=${searchQuery}&page=${currentPage - 1}`;
    }
  });

  const pageInfo = document.createElement("span");
  pageInfo.style.color = "var(--text-muted)";
  pageInfo.style.alignSelf = "center";
  pageInfo.style.fontSize = "0.85rem";
  pageInfo.textContent = `Page ${currentPage}`;

  const next = document.createElement("button");
  next.textContent = "Next →";
  next.disabled = !hasNextPage;
  next.addEventListener("click", () => {
    window.location.search = `?q=${searchQuery}&page=${currentPage + 1}`;
  });

  paginationContainer.appendChild(previous);
  paginationContainer.appendChild(pageInfo);
  paginationContainer.appendChild(next);
}

if (searchQuery) {
  fetch(`/api/${entityType}/search?q=${encodeURIComponent(searchQuery)}&page=${currentPage}`)
    .then((response) => response.json())
    .then(renderResults);
}

/* Details page specific styles */

.detail-card {
  display: flex;
  gap: 32px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  margin: 20px 24px;
  padding: 28px;
  box-shadow: var(--shadow);
}

.detail-cover {
  flex: 0 0 300px;
  order: 2;
}

.detail-cover img {
  width: 100%;
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow);
}

.detail-info {
  flex: 1;
  order: 1;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.detail-title {
  font-size: 1.8rem;
  font-weight: 700;
  background: var(--accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.detail-meta-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
}

.detail-tag {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 20px;
  padding: 6px 14px;
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.detail-tag strong {
  color: var(--accent);
}

.detail-synopsis-label {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.detail-synopsis {
  font-size: 0.9rem;
  color: var(--text-secondary);
  line-height: 1.7;
  max-height: 300px;
  overflow-y: auto;
  padding-right: 8px;
}

.detail-genres {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.genre-badge {
  background: var(--accent-glow);
  border: 1px solid var(--accent-dark);
  color: var(--accent-light);
  border-radius: 16px;
  padding: 4px 12px;
  font-size: 0.75rem;
  font-weight: 500;
}

@media (max-width: 700px) {
  .detail-card {
    flex-direction: column;
    margin: 12px;
    padding: 20px;
  }

  .detail-cover {
    order: 1;
    flex: none;
    max-width: 220px;
    align-self: center;
  }

  .detail-info {
    order: 2;
  }

  .detail-title {
    font-size: 1.3rem;
  }
}

// Search form
document.getElementById("search-form").addEventListener("submit", (e) => {
  e.preventDefault();
  const q = document.getElementById("text").value;
  const type = document.getElementById("type").value;
  if (q.trim()) {
    window.location.href = `/search/${type}?q=${encodeURIComponent(q)}`;
  }
});

const detailsContainer = document.getElementById("anime-details-container");
const id = window.location.pathname.split("/")[2];
const entityType = window.location.pathname.split("/")[1];

// Set the type selector to match current entity
document.getElementById("type").value = entityType;

function fetchAnime() {
  return fetch(`/api/${entityType}/${encodeURIComponent(id)}`).then((response) => response.json());
}

function renderAnime(data) {
  const d = data.data;
  detailsContainer.innerHTML = "";

  const card = document.createElement("div");
  card.className = "detail-card";

  // Cover image (right side)
  const cover = document.createElement("div");
  cover.className = "detail-cover";
  const img = document.createElement("img");
  img.src = d.images.jpg.large_image_url || d.images.jpg.image_url;
  img.alt = d.title;
  cover.appendChild(img);

  // Info (left side)
  const info = document.createElement("div");
  info.className = "detail-info";

  const title = document.createElement("h1");
  title.className = "detail-title";
  title.textContent = d.title;

  // Meta tags
  const metaGrid = document.createElement("div");
  metaGrid.className = "detail-meta-grid";

  const tags = [
    { label: "Score", value: d.score ?? "N/A" },
    { label: "Type", value: d.type || "Unknown" },
    { label: "Status", value: d.status || "Unknown" },
  ];

  if (entityType === "anime") {
    tags.push({ label: "Episodes", value: d.episodes ?? "?" });
  } else {
    tags.push({ label: "Chapters", value: d.chapters ?? "?" });
    tags.push({ label: "Volumes", value: d.volumes ?? "?" });
  }

  if (d.year) tags.push({ label: "Year", value: d.year });
  if (d.rating) tags.push({ label: "Rating", value: d.rating });

  tags.forEach((t) => {
    const tag = document.createElement("span");
    tag.className = "detail-tag";
    tag.innerHTML = `<strong>${t.label}:</strong> ${t.value}`;
    metaGrid.appendChild(tag);
  });

  // Genres
  const genres = document.createElement("div");
  genres.className = "detail-genres";
  if (d.genres) {
    d.genres.forEach((g) => {
      const badge = document.createElement("span");
      badge.className = "genre-badge";
      badge.textContent = g.name;
      genres.appendChild(badge);
    });
  }

  // Synopsis
  const synopsisLabel = document.createElement("div");
  synopsisLabel.className = "detail-synopsis-label";
  synopsisLabel.textContent = "Synopsis";

  const synopsis = document.createElement("div");
  synopsis.className = "detail-synopsis";
  synopsis.textContent = d.synopsis || "No synopsis available.";

  info.appendChild(title);
  info.appendChild(metaGrid);
  info.appendChild(genres);
  info.appendChild(synopsisLabel);
  info.appendChild(synopsis);

  card.appendChild(info);
  card.appendChild(cover);

  detailsContainer.appendChild(card);
}

fetchAnime().then(renderAnime);

