  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.detail-synopsis {
  font-size: 0.9rem;
  color: var(--text-secondary);
  line-height: 1.7;
  max-height: 300px;
  overflow-y: auto;
  padding-right: 8px;
}

.detail-genres {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.genre-badge {
  background: var(--accent-glow);
  border: 1px solid var(--accent-dark);
  color: var(--accent-light);
  border-radius: 16px;
  padding: 4px 12px;
  font-size: 0.75rem;
  font-weight: 500;
}

@media (max-width: 700px) {
  .detail-card {
    flex-direction: column;
    margin: 12px;
    padding: 20px;
  }

  .detail-cover {
    order: 1;
    flex: none;
    max-width: 220px;
    align-self: center;
  }

  .detail-info {
    order: 2;
  }

  .detail-title {
    font-size: 1.3rem;
  }
}

